const { ecoPopularityRank } = require\('./lib/openings.js'\);
" 2>/dev/null || node -e "
const data = require\('./data/openings.json'\);

function ecoPopularityRank\(eco\) {
  const letter = eco[0];
  const num = parseInt\(eco.slice\(1\), 10\);
  if \(letter === 'B'\) { if \(num >= 20\) return 1; if \(num >= 10\) return 8; if \(num >= 6\) return 12; return 14; }
  if \(letter === 'C'\) { if \(num >= 60\) return 2; if \(num >= 50\) return 3; if \(num >= 30\) return 9; if \(num >= 20\) return 10; return 4; }
  if \(letter === 'D'\) { if \(num >= 30 && num < 70\) return 5; if \(num >= 20\) return 11; if \(num >= 70\) return 13; return 16; }
  if \(letter === 'E'\) { if \(num >= 20 && num < 60\) return 6; if \(num >= 60\) return 7; return 15; }
  if \(letter === 'A'\) { if \(num >= 10 && num < 40\) return 17; if \(num >= 80\) return 18; if \(num >= 40 && num < 80\) return 19; return 20; }
  return 20;
}

const sorted = [...data].sort\(\(a, b\) => {
  const rd = ecoPopularityRank\(a.eco\) - ecoPopularityRank\(b.eco\);
  if \(rd !== 0\) return rd;
  return \(a.uci?.split\(' '\).length || 0\) - \(b.uci?.split\(' '\).length || 0\);
}\);

sorted.slice\(0, 15\).forEach\(o => console.log\(ecoPopularityRank\(o.eco\), o.eco, o.name\)\);
")

