Bash(node -e "
const data = require\('./data/openings.json'\);
const sic = data.filter\(o => o.eco === 'B20'\).slice\(0, 8\);
sic.forEach\(o => console.log\(JSON.stringify\(o.name\)\)\);
console.log\('---'\);
// Check naming pattern depth
const depths = {0:0, 1:0, 2:0, 3:0};
data.forEach\(o => {
  const colons = \(o.name.match\(/:/g\)||[]\).length;
  const commas = \(o.name.match\(/,/g\)||[]\).length;
  if \(commas >= 1\) depths[2]++;
  else if \(colons >= 1\) depths[1]++;
  else depths[0]++;
}\);
console.log\('No colon \(root\):', depths[0]\);
console.log\('Colon, no comma \(named variation\):', depths[1]\);
console.log\('Has comma \(sub-variation\):', depths[2]\);
")

